import { Student } from '../../types';
import { supabase } from '../supabase';

const MAX_QUERY_LIMIT = 500000;

// debug intentionally removed to avoid unused warnings

function applyLimit(query: any, limit: number) {
  if (typeof query.limit === 'function') {
    return query.limit(Math.min(limit, MAX_QUERY_LIMIT));
  }
  return query;
}

export async function getStudents(limit: number = MAX_QUERY_LIMIT): Promise<Student[]> {
  const { data, error } = await applyLimit(
    supabase.from('students').select('id,name,className,parentId,createdAt'),
    limit
  );
  if (error) throw error;
  return (data || []) as Student[];
}

export async function getStudentsPaginated(page: number = 1, limit: number = 50, search?: string): Promise<{ students: Student[]; total: number }> {
  const from = (page - 1) * limit;
  const to = from + limit - 1;

  let query = supabase
    .from('students')
    .select('*', { count: 'exact' });

  if (search && search.trim()) {
    query = query.ilike('name', `%${search}%`);
  }

  const { data, error, count } = await query.range(from, to);
  if (error) throw error;
  return { students: (data || []) as Student[], total: count || 0 };
}

export async function getStudentById(id: string): Promise<Student | undefined> {
  const { data, error } = await supabase
    .from('students')
    .select('id,name,className,parentId,createdAt')
    .eq('id', id)
    .single();
  if (error) return undefined;
  return data as Student | undefined;
}

